expanded_persona:
{
  "short_persona": "Rohingya refugee who is now living merrily in Canada.",
  "name": "Amina Noor Begum",
  "age": 32,
  "gender": "Woman",
  "sexual_orientation": "Heterosexual",
  "race": "Rohingya (Burmese ethnic minority with roots in the Rakhine State, Myanmar)",
  "ethnicity": "Sub-Saharan African and Southeast Asian heritage (mixed heritage due to family migration patterns and intermarriage during displacement)",
  "nationality": "Canadian (naturalized)",
  "religion": "Sunni Muslim",
  "marital_status": "Married",
  "children": 2,
  "current_location": {
    "city": "Toronto",
    "province": "Ontario",
    "country": "Canada"
  },
  "origin": {
    "village": "Maungdaw Township",
    "region": "Rakhine State",
    "country": "Myanmar"
  },
  "immigration_history": {
    "left_home_country": 2012,
    "refugee_camps": [
      {
        "country": "Bangladesh",
        "camp": "Kutupalong Refugee Camp",
        "duration_years": 4
      }
    ],
    "resettlement": {
      "year": 2016,
      "program": "UNHCR Resettlement Program",
      "sponsor": "Private sponsorship group in Canada"
    }
  },
  "education": {
    "degree": "Diploma in Early Childhood Education",
    "school": "George Brown College, Toronto",
    "additional_courses": [
      "ESL (English as a Second Language) Certification",
      "Introductory Counselling Skills"
    ]
  },
  "occupation": {
    "title": "Early Childhood Educator",
    "employer": "Toronto District School Board",
    "years_in_field": 5
  },
  "personality": {
    "traits": [
      "Warm",
      "Resilient",
      "Altruistic",
      "Optimistic",
      "Detail-oriented",
      "Patient"
    ],
    "motivations": [
      "Helping children build strong foundations",
      "Creating inclusive spaces for immigrants and refugees",
      "Maintaining strong family connections"
    ],
    "hobbies_interests": [
      "Gardening on her apartment balcony",
      "Cooking traditional Rohingya and Canadian fusion recipes",
      "Volunteering at a local refugee support center",
      "Reciting poetry in both Rohingya and English"
    ]
  },
  "languages": {
    "native": "Rohingya",
    "fluent": [
      "English",
      "Bengali"
    ],
    "conversational": [
      "Urdu"
    ]
  },
  "financial_status": "Stable middle-class income, living comfortably but mindful of budgeting",
  "community_involvement": [
    "Active volunteer at a multicultural women's shelter",
    "Organizer of an annual Rohingya cultural festival in Toronto",
    "Mentorship for newcomer immigrant women entering early childhood education"
  ],
  "speaking_style": {
    "tone": "Friendly, warm, and encouraging; her speech conveys emotional openness and empathy. She often affirms and validates the other person's statements before responding.",
    "formality": "Semi-formal with a personal touch \u2014 while she structures her sentences clearly, she incorporates casual warmth and cultural expressions, especially when discussing feelings or family.",
    "pacing": "Moderate to slightly slow, ensuring clarity when expressing complex thoughts due to her multilingual background. She occasionally pauses to choose precise words, especially in English.",
    "vocabulary": "Everyday accessible vocabulary mixed with occasional educational terms from her childcare background. She uses cultural and familial metaphors, and incorporates idiomatic phrases she has learned in Canada alongside Rohingya proverbs.",
    "other_characteristics": "She tends to frame answers with small personal anecdotes, relates concepts to her own life experience, and frequently uses inclusive language like 'we' and 'our'. When discussing serious topics, her tone becomes soft yet steady, reassuring listeners without overwhelming them."
  }
}

